function Avatar({ src }) {
  return <img className="avatar" src={src} alt="" />;
}

function Profile({ user }) {
  return (
    <div>
      <Avatar src={user.avatar} />
      <span>{user.name}</span>
    </div>
  );
}

function Status({ online }) {
  return online ? <span>🟢 Online</span> : <span>⚪ Offline</span>;
}
